var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"헤에, 이런 취향이었구나. 뭔가 묘한 기분이네….","JPN":"へえ、こういう趣味があったんだ。なんか変な気分……","ENG":"Ohh, so this is the kind of thing you like. It feels a bit weird...","TWN":"嘿～原來教練喜歡這種調調，有點奇妙的感覺……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"사실은 난 코치랑 궁합이 잘 안 맞을 줄 알았거든.","JPN":"実はコーチとは相性が合わないと思ってたからさ。","ENG":"I thought I wouldn't get along with you, to be honest.","TWN":"老實說，我原本以為我和教練不合。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"업무적으로나, 사적으로나?","JPN":"仕事でも、個人的にも？","ENG":"Business-wise and personal-wise.","TWN":"不管是工作上還是私底下？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데 막상 제안을 들으니까 싫지만은 않더라고.","JPN":"でも、いざ提案を聞いてみたら嫌ってわけでもなかったんだ。","ENG":"But I didn't hate the idea when you offered it.","TWN":"不過聽完教練的提議後，我並不覺得討厭。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 조금은 기대했다고 해야 하나?","JPN":"いや、少しは期待したっていうか？","ENG":"Well, I was actually a little awaited.","TWN":"不對，應該是說有點期待吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"코치를 따라다니면 온갖 골치 아픈 일에 시달릴 게 뻔한데도 말이야.","JPN":"コーチについて行ったら頭の痛いことばっかりだってわかってるのにさ。","ENG":"It's obvious I'd run into all kinds of trouble if I follow you around, Coach.","TWN":"因為跟著教練，一定會遇到各種麻煩事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐, 내 인생은 처음부터 줄곧 다른 녀석들 입맛대로 쓰기 좋은 총이었으니까.","JPN":"まあ、私の人生ハナっからずっと他人の好き勝手に使われる銃だったからね。","ENG":"To be fair, my life has always been a gun that others could just use to get their way.","TWN":"反正我的人生打從一開始，就像一把任人使用的槍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"펠리세트 같은 꼬맹이 손에 들리면 플라스틱 물총이고,","JPN":"フェリセットみたいなおこちゃまの手に渡ればプラスチックの水鉄砲だし、","ENG":"It's a toy water gun when kids like Félicette hold it,","TWN":"落到費莉塞特這個小鬼手裡，就是一把水槍，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"코치 손에 들리면 누구 한 놈 확실히 요절낼 권총이 되겠지.","JPN":"コーチの手に渡れば誰かを確実にやっつける拳銃になるだろうし。","ENG":"and it's a real handgun that can end a life if people like you hold it.","TWN":"要是落到教練手裡，就會變成一把致命的手槍吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"작가 중에 그런 말 한 사람도 있지 않나? 장전한 총알은 쏘라고 있는 거라고.","JPN":"作家にこんなこと言ってた人いなかったっけ？　充填した弾は撃つためにあるって。","ENG":"Isn't there a writer who said something about guns? That if it's not going to be fired, it shouldn't be hanging there.","TWN":"不是有某個作家說過？上膛的槍一定要發射。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"장식대에 걸릴지, 강바닥에 버려질지는 몰라도, 마지막 한 발만은 화려하게 터뜨리고 싶어.","JPN":"装飾台にかけられるか、川底に捨てられるかはわかんないけど、最後の一発だけは派手に撃ちたいんだ。","ENG":"I don't know if I'm gonna end up on a display case or on the bottom of the river, but I want to go out with a bang.","TWN":"雖然我這把槍不知道會被裝飾在牆上，還是丟棄在河裡，但我希望最後一發子彈能夠華麗射出。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"물총으로 못된 어른들을 혼쭐낸다는 건 요즘 애들도 안 믿을 소리고 말이야.","JPN":"水鉄砲で悪い大人をやっつけるなんて、今時のガキだって信じないよ。","ENG":"Even kids know that you can't punish bad adults with a water gun, don't you?","TWN":"說要拿水槍教訓壞人，這種話連小孩都不會信。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까 앞으로도 계속 지금 그대로 있어 줘. 나중 가서 너 요즘 변했다고 칭얼거리지 않게.","JPN":"だから、これからも今までどおりでいてくれよ。後になって最近変わったなとかぶつぶつ言われないようにさ。","ENG":"So, just stay the way you are now. I don't want to whine about how you've changed or something in the future.","TWN":"所以請繼續保持現狀，我不希望之後有機會抱怨你不是當初的你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};